def solve(arg1: dict) -> dict:
    challenges = {
        '12345': {'phaseEndTime': '2023-10-15T12:00:00Z'},
        '67890': {'phaseEndTime': '2023-10-20T12:00:00Z'}
    }

    challenge_id = arg1.get('challengeId')

    if not challenge_id:
        return {'error': 'Challenge ID cannot be empty'}

    if challenge_id not in challenges:
        return {'error': 'Challenge not found'}

    return challenges[challenge_id]
